    ? I
    : never;

/** Extract the schema from a Trait or Aspect constituent. */
type ConstituentSchema<C> =
    C extends Aspect<infer S> ? S : C extends Trait<infer S> ? S : Record<string, never>;

/** Merge the schemas of a tuple of constituents into a single schema. */
export type MergeSchemas<T extends readonly unknown[]> = UnionToIntersection<
    ConstituentSchema<T[number]>
> extends infer S
    ? S extends Schema
        ? S
        : Record<string, never>
    : Record<string, never>;

/**
 * The merged record delivered when reading an aspect.
 * Mirrors the SoA snapshot shape of a trait record.
 */
export type AspectRecord<TSchema extends Schema> = {
    [P in keyof TSchema]: TSchema[P] extends (...args: never[]) => unknown
        ? ReturnType<TSchema[P]>
