/** True when the entity has every constituent bit across all generations of the mask. */
function isComplete(entityMasks: number[][], eid: number, bitmasks: number[]): boolean {
    for (let gen = 0; gen < bitmasks.length; gen++) {
        const full = bitmasks[gen];
        if (!full) continue;
        const genMasks = entityMasks[gen];
        const entityMask = genMasks ? genMasks[eid] | 0 : 0;
        if ((entityMask & full) !== full) return false;
    }
    return true;
}

/**
 * True when the entity was complete immediately before an event that cleared
 * `eventBitflag` in `eventGen` (used for the remove transition).
 */
function wasCompleteBefore(
    entityMasks: number[][],
    eid: number,
    bitmasks: number[],
    eventGen: number,
    eventBitflag: number
): boolean {
    for (let gen = 0; gen < bitmasks.length; gen++) {
        const full = bitmasks[gen];
        if (!full) continue;
        const genMasks = entityMasks[gen];
        let entityMask = genMasks ? genMasks[eid] | 0 : 0;
        if (gen === eventGen) entityMask |= eventBitflag;
        if ((entityMask & full) !== full) return false;
    }
    return true;
}

function clearTrackers(group: AspectTrackingGroup, eid: number): void {
    const trackers = group.trackers;
    for (let gen = 0; gen < trackers.length; gen++) {
        const arr = trackers[gen];
        if (arr) arr[eid] = 0;
    }
}

function anyTracker(group: AspectTrackingGroup, eid: number): boolean {
    const trackers = group.trackers;
    for (let gen = 0; gen < trackers.length; gen++) {
        const arr = trackers[gen];
        if (arr && (arr[eid] | 0) !== 0) return true;
    }
    return false;
}

/**
 * Non-tracking check: an entity passes Not(aspect) constraints when it is
 * missing at least one constituent of every Not(aspect) group.
 */
export function passesNotAspects(world: World, query: QueryInstance, entity: Entity): boolean {
    const entityMasks = world[$internal].entityMasks;
    const eid = getEntityId(entity);

    for (let i = 0; i < query.notAspects.length; i++) {
        // If the aspect is complete, the entity is not "missing at least one".
        if (isComplete(entityMasks, eid, query.notAspects[i].bitmasks)) return false;
